#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#define MOD 786433
#define MAXN 100000

// Function to calculate the greatest common divisor (GCD) of two numbers
long long gcd(long long a, long long b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

// Function to calculate the expected productivity
long long calculateExpectedProductivity(int N, int K, int* Num, int* Den, int* B) {
    long long expectedProductivity = 0;
    // Calculate the expected productivity for each combination of K barmen out of N
    for (int i = 0; i < (1 << N); i++) {
        int count = 0;
        long long probability = 1;
        long long totalProductivity = 0;
        for (int j = 0; j < N; j++) {
            if ((i & (1 << j)) != 0) {
                count++;
                probability *= Num[j];
                probability /= Den[j];
                totalProductivity += B[j];
            } else {
                probability *= Den[j] - Num[j];
                probability /= Den[j];
            }
        }
        if (count == K) {
            expectedProductivity += probability * totalProductivity;
        }
    }
    // Simplify the fraction and calculate the result modulo MOD
    long long numerator = expectedProductivity;
    long long denominator = 1;
    for (int i = 0; i < N; i++) {
        denominator *= Den[i];
    }
    long long gcdValue = gcd(numerator, denominator);
    numerator /= gcdValue;
    denominator /= gcdValue;
    long long result = (numerator * denominator - 1) % MOD;
    return result;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int* Num = (int*)malloc(N * sizeof(int));
        int* Den = (int*)malloc(N * sizeof(int));
        int* B = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d %d %d", &Num[i], &Den[i], &B[i]);
        }
        long long result = calculateExpectedProductivity(N, K, Num, Den, B);
        printf("%lld\n", result);
        free(Num);
        free(Den);
        free(B);
    }
    return 0;
}

